import React, { useState, useEffect } from 'react';
import { Html5QrcodeScanner } from 'html5-qrcode';
import axios from 'axios';
import { useNavigate } from 'react-router-dom';
import { MapPin, ShieldCheck, ShieldAlert, ArrowLeft, RefreshCw, Camera, Send, Info } from 'lucide-react';
import { useAuth } from '../context/AuthContext';

const QRScanner = () => {
  const [scanResult, setScanResult] = useState(null);
  const [loading, setLoading] = useState(false);
  const [error, setError] = useState(null);
  const [location, setLocation] = useState(null);
  const [reporting, setReporting] = useState(false);
  const [description, setDescription] = useState('');
  const [reportSuccess, setReportSuccess] = useState(false);
  const { user } = useAuth();
  const navigate = useNavigate();

  useEffect(() => {
    let scanner = null;
    
    // Delay initialization slightly to ensure DOM is ready
    const timer = setTimeout(() => {
      scanner = new Html5QrcodeScanner('reader', {
         qrbox: { width: 250, height: 250 },
         fps: 10,
         rememberLastUsedCamera: true,
         supportedScanTypes: [0], // 0 = QR_CODE
         videoConstraints: {
           facingMode: "environment"
         }
       });

      scanner.render(onScanSuccess, onScanError);
    }, 500);

    function onScanSuccess(result) {
      if (scanner) {
        scanner.clear().catch(error => console.error("Failed to clear scanner", error));
      }
      try {
        const data = JSON.parse(result);
        handleValidation(data.id);
      } catch (e) {
        handleValidation(result);
      }
    }

    function onScanError(err) {
      // Log only once to avoid console flooding
      if (err && err.includes("Permission denied")) {
        setError("Camera permission denied. Please allow camera access in your browser settings.");
      }
    }

    // Get current location for validation
    if (navigator.geolocation) {
      navigator.geolocation.getCurrentPosition(
        (pos) => setLocation({ lat: pos.coords.latitude, lng: pos.coords.longitude }),
        (err) => setError("Please enable location services for validation")
      );
    }

    return () => {
      clearTimeout(timer);
      if (scanner) {
        scanner.clear().catch(error => console.error("Failed to clear scanner on unmount", error));
      }
    };
  }, []);

  const handleValidation = async (vendorId) => {
    setLoading(true);
    setError(null);
    try {
      if (!location) {
        throw new Error("Waiting for GPS location...");
      }

      const response = await axios.post('http://10.113.178.31:8080/api/scan/validate', {
        vendorId,
        latitude: location.lat,
        longitude: location.lng
      });
      setScanResult(response.data);
    } catch (err) {
      setError(err.response?.data?.message || err.message);
    } finally {
      setLoading(false);
    }
  };

  const handleReport = async () => {
    if (!scanResult) return;
    setReporting(true);
    try {
      await axios.post('http://10.113.178.31:8080/api/violations/report', {
        vendorId: scanResult.vendorId,
        gpsLatitude: location.lat,
        gpsLongitude: location.lng,
        description: description || "Location violation reported by public",
        imageProofUrl: "public_report.jpg", // In real app, upload actual photo
        capturedAt: new Date().toISOString()
      });
      setReportSuccess(true);
    } catch (err) {
      alert("Failed to report: " + (err.response?.data?.message || err.message));
    } finally {
      setReporting(false);
    }
  };

  const resetScanner = () => {
    window.location.reload();
  };

  return (
    <div className="min-h-screen bg-gray-900 text-white p-6">
      <div className="max-w-md mx-auto space-y-8">
        <div className="flex items-center gap-4">
          <button onClick={() => navigate(-1)} className="p-2 hover:bg-gray-800 rounded-full transition text-white">
            <ArrowLeft size={24} />
          </button>
          <div>
            <h1 className="text-2xl font-bold">{user ? 'Enforcement Scanner' : 'Public Report'}</h1>
            <p className="text-gray-400 text-sm">Scan vendor QR to verify location</p>
          </div>
        </div>

        {!scanResult && !error && (
          <div className="bg-white rounded-2xl overflow-hidden shadow-2xl p-4">
            <div id="reader" style={{ minHeight: '300px' }}></div>
            <div className="mt-4 text-center text-gray-500 text-sm flex items-center justify-center gap-2">
              <MapPin size={16} className="text-smc-blue" />
              {location ? `GPS: ${location.lat.toFixed(4)}, ${location.lng.toFixed(4)}` : "Detecting GPS..."}
            </div>
            {!user && (
              <div className="mt-4 p-3 bg-blue-50 text-smc-blue rounded-lg text-xs flex items-start gap-2">
                <Info size={16} className="shrink-0" />
                <span>You are scanning as a Public User. Your GPS location will be compared with the vendor's registered spot for verification.</span>
              </div>
            )}
          </div>
        )}

        {loading && (
          <div className="text-center py-12 flex flex-col items-center gap-4">
            <div className="animate-spin text-smc-gold"><RefreshCw size={48} /></div>
            <p className="text-lg font-semibold">Verifying Location...</p>
          </div>
        )}

        {error && (
          <div className="bg-red-500/10 border border-red-500 p-6 rounded-2xl text-center space-y-4">
            <ShieldAlert size={48} className="mx-auto text-red-500" />
            <h2 className="text-xl font-bold text-red-500">Scan Error</h2>
            <p className="text-gray-300">{error}</p>
            <button onClick={resetScanner} className="w-full bg-red-500 text-white py-3 rounded-xl font-bold hover:bg-red-600 transition">
              TRY AGAIN
            </button>
          </div>
        )}

        {scanResult && !reportSuccess && (
          <div className={`p-6 rounded-2xl border-t-8 shadow-2xl space-y-6 ${
            scanResult.validationStatus === 'VALID' ? 'bg-green-500/10 border-green-500' : 'bg-red-500/10 border-red-500'
          }`}>
            <div className="text-center">
              {scanResult.validationStatus === 'VALID' ? (
                <ShieldCheck size={64} className="mx-auto text-green-500" />
              ) : (
                <ShieldAlert size={64} className="mx-auto text-red-500" />
              )}
              <h2 className={`text-2xl font-bold mt-2 ${
                scanResult.validationStatus === 'VALID' ? 'text-green-500' : 'text-red-500'
              }`}>
                {scanResult.validationStatus === 'VALID' ? 'VERIFIED SPOT' : 'ILLEGAL SPOT'}
              </h2>
              <p className="text-gray-400 mt-1">{scanResult.message}</p>
            </div>

            <div className="bg-black/20 p-4 rounded-xl space-y-2">
              <div className="flex justify-between border-b border-white/5 pb-2">
                <span className="text-gray-400">Vendor</span>
                <span className="font-bold">{scanResult.vendorName}</span>
              </div>
              <div className="flex justify-between border-b border-white/5 pb-2">
                <span className="text-gray-400">ID</span>
                <span className="font-bold">{scanResult.vendorId}</span>
              </div>
              <div className="flex justify-between">
                <span className="text-gray-400">Distance</span>
                <span className="font-bold">{Math.round(scanResult.distance)} meters</span>
              </div>
            </div>

            {scanResult.validationStatus !== 'VALID' && (
              <div className="space-y-4">
                <div className="space-y-1">
                  <label className="text-xs text-gray-500 uppercase">Comment (Optional)</label>
                  <textarea 
                    value={description}
                    onChange={(e) => setDescription(e.target.value)}
                    className="w-full bg-black/30 border border-white/10 rounded-lg p-3 text-sm outline-none focus:border-red-500 transition"
                    placeholder="Describe the violation..."
                  />
                </div>
                <button 
                  onClick={handleReport}
                  disabled={reporting}
                  className="w-full bg-red-500 text-white py-4 rounded-xl font-bold hover:bg-red-600 transition shadow-lg flex items-center justify-center gap-2"
                >
                  <Send size={20} /> {reporting ? 'Submitting...' : 'REPORT VIOLATION'}
                </button>
                <p className="text-[10px] text-center text-gray-500">
                  A report will be sent to SMC with your current GPS location and timestamp.
                </p>
              </div>
            )}

            <button onClick={resetScanner} className="w-full border border-white/10 text-gray-400 py-3 rounded-xl font-bold hover:bg-white/5 transition">
              SCAN ANOTHER
            </button>
          </div>
        )}

        {reportSuccess && (
          <div className="bg-green-500/10 border border-green-500 p-8 rounded-2xl text-center space-y-4">
            <ShieldCheck size={64} className="mx-auto text-green-500" />
            <h2 className="text-2xl font-bold text-green-500">Report Submitted</h2>
            <p className="text-gray-300">Thank you for your report. SMC officials have been notified and an automatic fine has been issued to the vendor.</p>
            <button onClick={() => navigate('/login')} className="w-full bg-green-500 text-white py-3 rounded-xl font-bold hover:bg-green-600 transition">
              BACK TO HOME
            </button>
          </div>
        )}

        <div className="text-center text-xs text-gray-600 uppercase tracking-widest pt-8">
          SMC Smart City Enforcement
        </div>
      </div>
    </div>
  );
};

export default QRScanner;
